dialogue.llm_output:
以下是提取微信文章小标题和正文的增强方案，采用多级解析策略并保留内容结构：

```python
import requests
from bs4 import BeautifulSoup, Tag
import re
import json

def extract_wechat_content(url):
    """
    微信文章内容结构化提取专业版
    返回：{
        "title": 主标题,
        "sections": [
            {"type": "subtitle", "content": "小标题1", "level": 2},
            {"type": "paragraph", "content": "段落内容..."},
            {"type": "image", "url": "图片地址"},
            # 其他内容元素...
        ]
    }
    """
    result = {"title": "", "sections": []}
    headers = {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36',
        'Accept-Encoding': 'gzip, deflate'
    }

    try:
        response = requests.get(url, headers=headers, timeout=10)
        response.raise_for_status()
        soup = BeautifulSoup(response.text, 'html.parser')

        # 提取主标题
        title = soup.find('h1', {'id': 'activity-name'}) or soup.find('meta', property='og:title')
        result['title'] = title.get_text(strip=True) if isinstance(title, Tag) else ""

        # 定位正文容器（兼容新旧版微信编辑器）
        content_containers = [
            soup.find('div', id='js_content'),  # 新版
            soup.find('div', class_='rich_media_content'),  # 旧版
            soup.find('div', id='page-content')  # 备用
        ]
        content_div = next((c for c in content_containers if c is not None), None)

        if not content_div:
            return result

        # 内容类型识别规则
        element_rules = [
            {  # 小标题检测
                'condition': lambda t: t.name in ['h2', 'h3', 'h4'] and not t.get('class'),
                'handler': lambda e: {
                    "type": "subtitle",
                    "content": clean_text(e.get_text()),
                    "level": int(e.name[1])
                }
            },
            {  # 段落文本
                'condition': lambda t: t.name == 'p' and not is_empty_paragraph(t),
                'handler': lambda e: {
                    "type": "paragraph",
                    "content": clean_paragraph(e)
                }
            },
            {  # 图片检测
                'condition': lambda t: t.name == 'img' and t.get('data-src'),
                'handler': lambda e: {
                    "type": "image",
                    "url": e['data-src'].split('?')[0]  # 去除图片后缀参数
                }
            },
            {  # 代码块检测
                'condition': lambda t: t.name == 'pre' or (t.get('class') and 'code-snippet' in t.get('class')),
                'handler': lambda e: {
                    "type": "code",
                    "content": e.get_text(strip=False)
                }
            }
        ]

        # 递归遍历内容节点
        def process_element(element):
            if not isinstance(element, Tag):
                return

            # 先检查当前元素是否符合规则
            matched = False
            for rule in element_rules:
                if rule['condition'](element):
                    result['sections'].append(rule['handler'](element))
                    matched = True
                    break

            # 未匹配规则则遍历子元素
            if not matched:
                for child in element.children:
                    process_element(child)

        process_element(content_div)

        return result

    except Exception as e:
        print(f"提取失败：{str(e)}")
        return result

def clean_text(text):
    """深度清理微信特殊字符"""
    return re.sub(
        r'[\u200b\u200c\u200d\ufeff\u00a0\xa0\u3000]+',
        ' ',
        text.strip()
    ).replace('\r\n', '\n')

def clean_paragraph(p_tag):
    """处理复杂段落结构"""
    # 移除空span和无效标签
    for elem in p_tag.find_all(['span', 'strong']):
        if not elem.get_text(strip=True):
            elem.decompose()

    # 处理换行符
    text = '\n'.join([t.strip() for t in p_tag.stripped_strings])
    return clean_text(text)

def is_empty_paragraph(p_tag):
    """检测无效段落"""
    if not p_tag.get_text(strip=True):
        return True
    # 过滤微信的空白占位符
    return bool(re.search(r'^[\s\u200b]*$', p_tag.get_text()))

# 使用示例
if __name__ == "__main__":
    article_url = "https://mp.weixin.qq.com/s/真实文章ID"
    content = extract_wechat_content(article_url)

    print(f"主标题：{content['title']}\n")
    print("文章结构：")
    for i, section in enumerate(content['sections'], 1):
        if section['type'] == 'subtitle':
            print(f"\n【小标题 {section['level']} 级】{section['content']}")
        elif section['type'] == 'paragraph':
            print(f"段落 {i}: {section['content'][:60]}...")
        elif section['type'] == 'image':
            print(f"[图片] {section['url']}")

    # 保存结构化数据
    with open('wechat_article.json', 'w', encoding='utf-8') as f:
        json.dump(content, f, ensure_ascii=False, indent=2)
```

### 功能亮点：
1. **智能结构识别**：
   - 支持多级小标题（h2-h4）
   - 区分段落、图片、代码块等元素
   - 自动过滤微信空白占位符

2. **深度内容清洗**：
   - 处理微信特殊不可见字符
   - 清理冗余HTML标签
   - 智能段落合并

3. **结构化输出**：
```json
{
  "title": "文章主标题",
  "sections": [
    {"type": "subtitle", "content": "第一节", "level": 2},
    {"type": "paragraph", "content": "正文内容..."},
    {"type": "image", "url": "https://mmbiz.qpic.cn/...},
    {"type": "code", "content": "print('代码示例')"}
  ]
}
```

### 扩展功能建议：
1. **添加Markdown转换**：
```python
def to_markdown(content):
    md = [f"# {content['title']}\n"]
    for sec in content['sections']:
        if sec['type'] == 'subtitle':
            md.append(f"\n{'#' * sec['level']} {sec['content']}\n")
        elif sec['type'] == 'paragraph':
            md.append(f"{sec['content']}\n")
        elif sec['type'] == 'image':
            md.append(f"![图片]({sec['url']})\n")
    return '\n'.join(md)
```

2. **添加PDF导出**：
```python
from fpdf import FPDF

def export_pdf(content, filename):
    pdf = FPDF()
    pdf.add_font('SimSun', '', 'SimSun.ttf', uni=True)
    pdf.set_font('SimSun', size=12)

    pdf.add_page()
    pdf.multi_cell(0, 10, txt=content['title'], align='C')

    for sec in content['sections']:
        if sec['type'] == 'subtitle':
            pdf.set_font(size=14, style='B')
            pdf.cell(0, 10, txt=sec['content'], ln=1)
            pdf.set_font(size=12)
        elif sec['type'] == 'paragraph':
            pdf.multi_cell(0, 10, txt=sec['content'])

    pdf.output(filename)
```

3. **添加关键词提取**（需jieba库）：
```python
import jieba.analyse

def extract_keywords(content, topK=10):
    text = '\n'.join([
        sec['content'] for sec in content['sections']
        if sec['type'] in ['subtitle', 'paragraph']
    ])
    return jieba.analyse.extract_tags(text, topK=topK)
```

